Logging, checkpoint, and TensorBoard utilities.
"""
import os
import time
import torch
import numpy as np
from collections import deque
import logging


def setup_logger(name="train", log_dir="logs", console=True):
    """Set up logger with file and console handlers."""
    os.makedirs(log_dir, exist_ok=True)
    logger = logging.getLogger(name)
    logger.setLevel(logging.INFO)
    logger.handlers = []

    formatter = logging.Formatter("%(asctime)s [%(levelname)s] %(message)s", datefmt="%H:%M:%S")

    file_handler = logging.FileHandler(os.path.join(log_dir, f"{name}.log"))
    file_handler.setFormatter(formatter)
    logger.addHandler(file_handler)

    if console:
        console_handler = logging.StreamHandler()
        console_handler.setFormatter(formatter)
        logger.addHandler(console_handler)

    return logger


class TensorBoardWriter:
    """Lightweight TensorBoard wrapper."""

    def __init__(self, log_dir="logs/runs"):
        os.makedirs(log_dir, exist_ok=True)
        from torch.utils.tensorboard import SummaryWriter
        self.writer = SummaryWriter(log_dir=log_dir, flush_secs=10)
        self.step = 0

    def add_scalar(self, tag, value, step=None):
        if step is None:
            step = self.step
        self.writer.add_scalar(tag, value, step)

    def add_scalars(self, tag, values, step=None):
        if step is None:
            step = self.step
        self.writer.add_scalars(tag, values, step)

    def increment(self):
        self.step += 1

    def close(self):
        self.writer.close()


class Trackers:
    """Track and log training metrics."""

    def __init__(self, window_size=100):
        self.window_size = window_size
        self.episode_rewards = deque(maxlen=window_size)
        self.episode_lengths = deque(maxlen=window_size)
        self.losses = {}

    def update(self, reward, length, **loss_vals):
        self.episode_rewards.append(reward)
        self.episode_lengths.append(length)
        for k, v in loss_vals.items():
            if k not in self.losses:
                self.losses[k] = deque(maxlen=self.window_size)
            self.losses[k].append(v)

    def summary(self):
        r = list(self.episode_rewards)
        l = list(self.episode_lengths)
        stats = {
            "reward_mean": np.mean(r),
            "reward_std": np.std(r),
            "reward_min": np.min(r),
            "reward_max": np.max(r),
            "length_mean": np.mean(l),
        }
        for k, v in self.losses.items():
            stats[f"loss/{k}"] = np.mean(list(v))
        return stats


def save_checkpoint(path, epoch, model, optimizer, extra=None):
    """Save model checkpoint."""
    os.makedirs(os.path.dirname(path), exist_ok=True)
    ckpt = {
